import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const API_KEY = process.env.API_KEY || "";

export class PortfolioAIService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: API_KEY });
  }

  async getChatResponse(message: string, history: { role: 'user' | 'model', parts: { text: string }[] }[]): Promise<string> {
    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: [
            ...history.map(h => ({ role: h.role, parts: h.parts })),
            { role: 'user', parts: [{ text: message }] }
        ],
        config: {
          systemInstruction: `You are the AI version of the user. Your goal is to represent them to potential recruiters or visitors.
          Personal Info:
          - Name: Portfolio Owner
          - Skills: React, TypeScript, Node.js, Tailwind, Gemini API, UI/UX Design.
          - Vibe: Professional yet friendly, creative, and tech-savvy.
          - Goal: Help visitors learn about projects and skills.
          Answer briefly and concisely. If asked about salary or private info, politely decline and offer to discuss via direct email.`,
          temperature: 0.8,
          maxOutputTokens: 250,
        },
      });

      return response.text || "I'm sorry, I'm having trouble thinking right now.";
    } catch (error) {
      console.error("Gemini Error:", error);
      return "Hello! I am currently taking a quick power nap. Please reach out via the contact form!";
    }
  }
}

export const aiService = new PortfolioAIService();

