import React, { useEffect, useRef, useState } from 'react';

const Hero: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [glitchText, setGlitchText] = useState("Experiences");

  // Matrix Rain Animation
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const resizeCanvas = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    window.addEventListener('resize', resizeCanvas);
    resizeCanvas();

    const characters = "0101010101010101010101010101010101010101010101010101010101010101";
    const fontSize = 16;
    const columns = Math.floor(canvas.width / fontSize);
    const drops: number[] = new Array(columns).fill(1);

    const draw = () => {
      // Slightly transparent black to create the trail effect
      ctx.fillStyle = 'rgba(5, 5, 5, 0.05)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.fillStyle = '#0ff'; // Cyan for a modern "hacker" look
      ctx.font = `${fontSize}px monospace`;

      for (let i = 0; i < drops.length; i++) {
        const text = characters.charAt(Math.floor(Math.random() * characters.length));
        ctx.fillText(text, i * fontSize, drops[i] * fontSize);

        if (drops[i] * fontSize > canvas.height && Math.random() > 0.975) {
          drops[i] = 0;
        }
        drops[i]++;
      }
    };

    const interval = setInterval(draw, 33);

    return () => {
      clearInterval(interval);
      window.removeEventListener('resize', resizeCanvas);
    };
  }, []);

  // Simple Glitch Text Effect
  useEffect(() => {
    const original = "Experiences";
    const letters = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789!@#$%^&*()";
    let iteration = 0;

    const interval = setInterval(() => {
      setGlitchText(prev => 
        original.split("").map((char, index) => {
          if(index < iteration) return original[index];
          return letters[Math.floor(Math.random() * 26)];
        }).join("")
      );

      if(iteration >= original.length) {
        clearInterval(interval);
        // Reset after some time for continuous effect
        setTimeout(() => {
            iteration = 0;
        }, 3000);
      }

      iteration += 1 / 3;
    }, 30);

    return () => clearInterval(interval);
  }, []);

  return (
    <section className="relative min-h-screen flex items-center justify-center overflow-hidden pt-20">
      {/* Matrix Background */}
      <canvas 
        ref={canvasRef} 
        className="absolute inset-0 z-0 opacity-20 pointer-events-none"
      />

      <div className="container mx-auto px-6 relative z-10">
        <div className="max-w-4xl mx-auto text-center">
          <div className="inline-block px-4 py-1.5 mb-6 rounded-full glass text-xs font-semibold tracking-widest text-cyan-400 border border-cyan-400/20 uppercase animate-pulse">
            SYSTEM ACCESS: GRANTED
          </div>

          <h1 className="text-5xl md:text-8xl font-black font-heading leading-tight mb-8">
            <span className="block opacity-80 mb-2 text-3xl md:text-5xl">INJECTING CODE INTO</span>
            <span className="bg-gradient-to-r from-cyan-400 via-blue-500 to-purple-600 bg-clip-text text-transparent italic inline-block min-w-[300px]">
              {glitchText}
            </span>
          </h1>

          <div className="bg-black/40 backdrop-blur-md p-6 rounded-xl border border-white/5 max-w-2xl mx-auto mb-10 text-left font-mono">
            <p className="text-cyan-400 text-sm mb-2 font-bold">$ whoami</p>
            <p className="text-gray-300 text-lg leading-relaxed mb-4">
              Full-stack developer focused on building secure, scalable, and visually stunning digital architecture.
