            <p className="text-green-500 text-sm animate-pulse">_ root@portfolio:~$</p>
          </div>

          <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
            <a href="#projects" className="w-full sm:w-auto px-8 py-4 bg-cyan-500 text-black font-bold rounded-xl hover:bg-cyan-400 transition-all flex items-center justify-center gap-2 group shadow-lg shadow-cyan-500/20">
