  constructor() {
    // Always use process.env.API_KEY directly when initializing the GoogleGenAI client
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async getChatResponse(message: string, history: { role: 'user' | 'model', parts: { text: string }[] }[]): Promise<string> {
    try {
      // Call generateContent with the model name and contents directly
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: [
            ...history.map(h => ({ role: h.role, parts: h.parts })),
            { role: 'user', parts: [{ text: message }] }
        ],
        config: {
          systemInstruction: `You are the AI version of the user. Your goal is to represent them to potential recruiters or visitors.
          Personal Info:
